$ErrorActionPreference = 'Stop'
$baseDir = 'C:\Users\Administrator\Desktop\SHINJIN\1 CELL 조립 장비\PLC RAW\ST_XEC'
$outDir = Join-Path $baseDir 'output'
if (-not (Test-Path $outDir)) { New-Item -ItemType Directory -Path $outDir | Out-Null }

$files = @(
    'ST_01_MAIN',
    'ST_02_HMI',
    'ST_03_INPUT',
    'ST_04_OUTPUT',
    'ST_05_ALARM',
    'ST_06_SERVO',
    'ST_10_제품투입배출',
    'ST_11_플런저',
    'ST_12_스프링015',
    'ST_13_스프링023',
    'ST_14_댐퍼',
    'ST_15_구리스도포',
    'ST_16_코어',
    'ST_17_프레임',
    'ST_18_작동력검사',
    'ST_19_통전검사',
    'ST_20_불량배출'
)

$csvHeader = '변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션'
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
$cp949 = [System.Text.Encoding]::GetEncoding(949)

foreach ($fname in $files) {
    $srcPath = Join-Path $baseDir "$fname.st"
    if (-not (Test-Path $srcPath)) {
        Write-Host "SKIP: $srcPath not found"
        continue
    }

    # UTF-8로 읽기
    $lines = [System.IO.File]::ReadAllLines($srcPath, $utf8NoBom)
    $totalLines = $lines.Count

    # 위치 찾기
    $programLine = -1
    $varStart = -1
    $varEnd = -1
    $endProgram = -1

    for ($i = 0; $i -lt $totalLines; $i++) {
        $trimmed = $lines[$i].Trim()
        if ($programLine -eq -1 -and $trimmed -match '^PROGRAM\s+') {
            $programLine = $i
        }
        if ($varStart -eq -1 -and $trimmed -eq 'VAR') {
            $varStart = $i
        }
        if ($varStart -ne -1 -and $varEnd -eq -1 -and $trimmed -eq 'END_VAR') {
            $varEnd = $i
        }
        if ($trimmed -eq 'END_PROGRAM') {
            $endProgram = $i
        }
    }

    # === Step A: _code.st 생성 ===
    # VAR 블록이 있으면 END_VAR 다음부터, 없으면 PROGRAM 다음부터
    # END_PROGRAM 이전까지
    $codeStartIdx = 0
    if ($varEnd -ne -1) {
        $codeStartIdx = $varEnd + 1
    } elseif ($programLine -ne -1) {
        $codeStartIdx = $programLine + 1
    }

    $codeEndIdx = $totalLines - 1
    if ($endProgram -ne -1) {
        $codeEndIdx = $endProgram - 1
    }

    # 코드 라인 추출
    $codeLines = @()
    for ($i = $codeStartIdx; $i -le $codeEndIdx; $i++) {
        $codeLines += $lines[$i]
    }

    # 앞뒤 빈줄 제거
    while ($codeLines.Count -gt 0 -and $codeLines[0].Trim() -eq '') {
        $codeLines = $codeLines[1..($codeLines.Count - 1)]
    }
    while ($codeLines.Count -gt 0 -and $codeLines[$codeLines.Count - 1].Trim() -eq '') {
        if ($codeLines.Count -eq 1) { $codeLines = @(); break }
        $codeLines = $codeLines[0..($codeLines.Count - 2)]
    }

    $codeContent = ($codeLines -join "`r`n") + "`r`n"
    $codePath = Join-Path $outDir "${fname}_code.st"
    [System.IO.File]::WriteAllText($codePath, $codeContent, $utf8NoBom)

    # === Step B: _var.csv 생성 ===
    $csvLines = @($csvHeader)

    if ($varStart -ne -1 -and $varEnd -ne -1) {
        for ($i = $varStart + 1; $i -lt $varEnd; $i++) {
            $line = $lines[$i].Trim()
            if ($line -eq '' -or $line -match '^\(\*.*\*\)$') { continue }

            # 주석 추출
            $comment = ''
            if ($line -match '\(\*\s*(.*?)\s*\*\)') {
                $comment = $Matches[1]
                $line = $line -replace '\(\*.*?\*\)', ''
                $line = $line.Trim()
            }

            # 세미콜론 제거
            $line = $line.TrimEnd(';').Trim()

            if ($line -eq '') { continue }

            # 변수 파싱: name [AT %addr] : TYPE [:= INIT]
            $varName = ''
            $varType = ''
            $varInit = ''

            if ($line -match '^(\S+)\s+AT\s+%(\S+)\s*:\s*(.+)$') {
                # AT % 바인딩 있는 경우
                $varName = $Matches[1]
                # addr는 무시 (메모리 할당 열은 비워둠)
                $typeAndInit = $Matches[3].Trim()
            } elseif ($line -match '^(\S+)\s*:\s*(.+)$') {
                # 일반 변수
                $varName = $Matches[1]
                $typeAndInit = $Matches[2].Trim()
            } else {
                continue
            }

            # 초기값 분리
            if ($typeAndInit -match '^(\S+)\s*:=\s*(.+)$') {
                $varType = $Matches[1]
                $varInit = $Matches[2].Trim()
            } else {
                $varType = $typeAndInit.Trim()
                $varInit = ''
            }

            # CSV 이스케이프 (쉼표나 따옴표 포함 시)
            $comment = $comment -replace '"', '""'
            if ($comment -match ',') { $comment = "`"$comment`"" }

            $csvLines += "VAR,$varName,$varType,,$varInit,0,0,0,0,0,0,$comment"
        }
    }

    $csvContent = ($csvLines -join "`r`n") + "`r`n"
    $csvPath = Join-Path $outDir "${fname}_var.csv"
    $csvBytes = $cp949.GetBytes($csvContent)
    [System.IO.File]::WriteAllBytes($csvPath, $csvBytes)

    $varCount = $csvLines.Count - 1
    Write-Host "OK: $fname -> _code.st ($($codeLines.Count) lines), _var.csv ($varCount vars)"
}

Write-Host "`nDone. Output: $outDir"

# process_st.ps1 - Split ST files into _code.st and _var.csv
$ErrorActionPreference = 'Stop'
$baseDir = $PSScriptRoot
$outDir = Join-Path $baseDir 'output'
if (-not (Test-Path $outDir)) { New-Item -ItemType Directory -Path $outDir | Out-Null }

$stFiles = Get-ChildItem -Path $baseDir -Filter 'ST_*.st' | Where-Object { $_.Name -notmatch '_code\.st$' }
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
$cp949 = [System.Text.Encoding]::GetEncoding(949)
$csvHdr = [char]48320 + [char]49688 + ' ' + [char]51333 + [char]47448 + ',' + [char]51060 + [char]47492 + ',' + [char]53440 + [char]51077 + ',' + [char]47700 + [char]47784 + [char]47532 + ' ' + [char]54624 + [char]45817 + ',' + [char]52488 + [char]44592 + [char]44050 + ',' + [char]47532 + [char]53580 + [char]51064 + ',' + [char]51069 + [char]44592 + ' ' + [char]51204 + [char]50857 + ',EIP,OPC UA,HMI,' + [char]52629 + ',' + [char]46356 + [char]49828 + [char]53356 + [char]47549 + [char]49496

foreach ($f in $stFiles) {
    $fname = [System.IO.Path]::GetFileNameWithoutExtension($f.Name)
    $lines = [System.IO.File]::ReadAllLines($f.FullName, $utf8NoBom)
    $total = $lines.Count
    $pLine = -1; $vStart = -1; $vEnd = -1; $eProg = -1
    for ($i = 0; $i -lt $total; $i++) {
        $t = $lines[$i].Trim()
        if ($pLine -eq -1 -and $t -match '^PROGRAM\s+') { $pLine = $i }
        if ($vStart -eq -1 -and $t -eq 'VAR') { $vStart = $i }
        if ($vStart -ne -1 -and $vEnd -eq -1 -and $t -eq 'END_VAR') { $vEnd = $i }
        if ($t -eq 'END_PROGRAM') { $eProg = $i }
    }
    $cs = 0
    if ($vEnd -ne -1) { $cs = $vEnd + 1 }
    elseif ($pLine -ne -1) { $cs = $pLine + 1 }
    $ce = $total - 1
    if ($eProg -ne -1) { $ce = $eProg - 1 }
    $cl = New-Object System.Collections.Generic.List[string]
    for ($i = $cs; $i -le $ce; $i++) { $cl.Add($lines[$i]) }
    while ($cl.Count -gt 0 -and $cl[0].Trim() -eq '') { $cl.RemoveAt(0) }
    while ($cl.Count -gt 0 -and $cl[$cl.Count-1].Trim() -eq '') { $cl.RemoveAt($cl.Count-1) }
    $cc = ($cl -join "`r`n") + "`r`n"
    [System.IO.File]::WriteAllText((Join-Path $outDir "${fname}_code.st"), $cc, $utf8NoBom)

    $csv = New-Object System.Collections.Generic.List[string]
    $csv.Add($csvHdr)
    if ($vStart -ne -1 -and $vEnd -ne -1) {
        for ($i = $vStart+1; $i -lt $vEnd; $i++) {
            $ln = $lines[$i].Trim()
            if ($ln -eq '' -or ($ln.StartsWith('(*') -and $ln.EndsWith('*)'))) { continue }
            $cmt = ''
            if ($ln -match '\(\*\s*(.*?)\s*\*\)') {
                $cmt = $Matches[1]
                $ln = ($ln -replace '\(\*.*?\*\)', '').Trim()
            }
            $ln = $ln.TrimEnd(';').Trim()
            if ($ln -eq '') { continue }
            $vn = ''; $vt = ''; $vi = ''
            if ($ln -match '^(\S+)\s+AT\s+%(\S+)\s*:\s*(.+)$') {
                $vn = $Matches[1]; $tai = $Matches[3].Trim()
            } elseif ($ln -match '^(\S+)\s*:\s*(.+)$') {
                $vn = $Matches[1]; $tai = $Matches[2].Trim()
            } else { continue }
            if ($tai -match '^(\S+)\s*:=\s*(.+)$') {
                $vt = $Matches[1]; $vi = $Matches[2].Trim()
            } else { $vt = $tai }
            $cmt = $cmt -replace '"','""'
            if ($cmt -match ',') { $cmt = "`"$cmt`"" }
            $csv.Add("VAR,$vn,$vt,,$vi,0,0,0,0,0,0,$cmt")
        }
    }
    $csvText = ($csv -join "`r`n") + "`r`n"
    [System.IO.File]::WriteAllBytes((Join-Path $outDir "${fname}_var.csv"), $cp949.GetBytes($csvText))
    $vc = $csv.Count - 1
    Write-Host ("OK: {0} -> code({1}L) var({2})" -f $fname, $cl.Count, $vc)
}
Write-Host "Done."
